function activate(context) {
  var en = context.locale === 'en-US';
  var count = context.files.getAll().length;
  context.ui.addToolbarButton({
    icon: 'folder',
    label: en ? ('Files ' + count) : ('文件 ' + count),
    onClick: function () {
      context.ui.showModal(
        en ? 'Workspace' : '工作区',
        en
          ? ('There are ' + count + ' files in the editor.')
          : ('当前编辑器中共有 ' + count + ' 个文件。')
      );
    },
  });
}
